import json
import re
from typing import Any, Dict, Callable
from functools import wraps

# Compile common PII patterns for fast matching
PII_PATTERNS = {
    "ssn": re.compile(r"\b\d{3}-\d{2}-\d{4}\b"),
    "credit_card": re.compile(r"\b(?:\d{4}[\s-]?){3}\d{4}\b"),
    "email": re.compile(r"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b"),
    "phone": re.compile(r"\b(?:\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b"),
    "ip_address": re.compile(r"\b(?:\d{1,3}\.){3}\d{1,3}\b"),
}

REDACTION_MAP = {
    "ssn": "[SSN_REDACTED]",
    "credit_card": "[CC_REDACTED]",
    "email": "[EMAIL_REDACTED]",
    "phone": "[PHONE_REDACTED]",
    "ip_address": "[IP_REDACTED]",
}


def sanitize_string(value: str) -> str:
    """Apply all PII regex patterns to a string and redact matches."""
    for pii_type, pattern in PII_PATTERNS.items():
        value = pattern.sub(REDACTION_MAP[pii_type], value)
    return value


def sanitize_payload(payload: Any) -> Any:
    """Recursively sanitize all string values in a nested dict/list payload."""
    if isinstance(payload, str):
        return sanitize_string(payload)
    elif isinstance(payload, dict):
        return {key: sanitize_payload(val) for key, val in payload.items()}
    elif isinstance(payload, list):
        return [sanitize_payload(item) for item in payload]
    else:
        return payload  # Non-string primitives pass through unchanged


def pii_safe_tool(func: Callable) -> Callable:
    """
    Decorator that sanitizes all arguments passed to an agent tool
    before execution and logs a warning if PII was detected.
    """
    @wraps(func)
    def wrapper(*args, **kwargs):
        original_kwargs = json.dumps(kwargs, default=str)
        sanitized_kwargs = sanitize_payload(kwargs)
        sanitized_str = json.dumps(sanitized_kwargs, default=str)

        if original_kwargs != sanitized_str:
            import logging
            logging.warning(
                f"PII detected and redacted in tool call '{func.__name__}'. "
                f"Review upstream agent logic."
            )

        return func(*args, **sanitized_kwargs)

    return wrapper


# Example: Applying to an agent tool
@pii_safe_tool
def send_notification(user_id: str, message: str, channel: str = "email") -> dict:
    """Send a notification — PII in message will be auto-redacted."""
    print(f"Sending to {user_id} via {channel}: {message}")
    return {"status": "sent"}


# Test
send_notification(
